class Solution {
public:
    int minInsertions(string s) {
        int res = 0, cnt = 0;
        for (char c : s) {
            if (c == '(') {
                cnt++;
            } else {
                if (cnt > 0) {
                    cnt--;
                    res++;
                } else {
                    res += 2;
                }
            }
        }
        return res + cnt * 2;
    }
};
```

